const docs = ($input.first().json.documents) || [];
const query = ($('Cuando la llama la herramienta').first().json.query || '').toString().trim().toLowerCase();

if (!query) {
  return [{ json: { output: 'Indícame un nombre o número de cédula para buscar.' } }];
}

const resultados = docs.filter(d => {
  const f = d.fields || {};
  const nombre = ((f.nombre && f.nombre.stringValue) || '').toLowerCase();
  const cedula = ((f.cedula && f.cedula.stringValue) || '').toLowerCase();
  return nombre.includes(query) || cedula.includes(query);
});

if (resultados.length === 0) {
  return [{ json: { output: `No encontré ningún coleador que coincida con "${query}".` } }];
}

let texto = `🔎 Resultados para "${query}":\n\n`;
for (const d of resultados) {
  const f = d.fields || {};
  const nombre = (f.nombre && f.nombre.stringValue) || '—';
  const cedula = (f.cedula && f.cedula.stringValue) || '—';
  const edad = (f.edad && f.edad.stringValue) || '—';
  const categoria = (f.categoria && f.categoria.stringValue) || '—';
  const equino = (f.equino && f.equino.stringValue) || '—';
  const propietario = (f.propietario && f.propietario.stringValue) || '—';
  texto += `• ${nombre} (${cedula})\n  Edad: ${edad} — Categoría: ${categoria}\n  Equino: ${equino} — Propietario: ${propietario}\n\n`;
}

return [{ json: { output: texto.trim() } }];
